function generateGuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

return {
  "sessionId": $input.first().json.sessionId || generateGuid(),
  "from": $input.first().json.from,
  "subject": $input.first().json.subject,
  "content": $input.first().json.content
}

// Extrahiere Format aus dem Input
const content = $input.first().json.content || '';
const output = $input.first().json.output || '';

// Erkenne Format aus dem Content oder nutze Default
let format = 'markdown';
let fileExtension = 'md';
let mimeType = 'text/markdown';

if (content.toLowerCase().includes('ausgabeformat: html') || content.toLowerCase().includes('format: html')) {
  format = 'html';
  fileExtension = 'html';
  mimeType = 'text/html';
}

// Erstelle Dateinamen mit Zeitstempel
const timestamp = new Date().toISOString().split('T')[0];
const filename = `task_${timestamp}.${fileExtension}`;

// Email Body Text
const emailBody = `Ihre Aufgabe wurde erfolgreich erstellt.\n\nDie vollständige Aufgabe finden Sie im Anhang: ${filename}\n\nViel Erfolg!`;

// Erstelle Binary-Daten mit prepareBinaryData
const fileBuffer = Buffer.from(output, 'utf-8');
const binaryData = await this.helpers.prepareBinaryData(fileBuffer, filename, mimeType);

return [{
  json: {
    output: output,
    emailBody: emailBody,
    filename: filename,
    format: format
  },
  binary: {
    data: binaryData
  }
}];
